const db = require('./db');
const crypto = require('crypto');

function generateCode() {
  return crypto.randomBytes(4).toString('hex').toUpperCase();
}

function createReferral(referrerId) {
  const code   = generateCode();
  const result = db.prepare(
    'INSERT INTO referrals (referrer_id, code) VALUES (?, ?)'
  ).run(referrerId, code);
  return { id: result.lastInsertRowid, code };
}

function getReferralByCode(code) {
  return db.prepare('SELECT * FROM referrals WHERE code = ?').get(code);
}

function getReferralsByUser(userId) {
  return db.prepare('SELECT * FROM referrals WHERE referrer_id = ?').all(userId);
}

function redeemReferral(code, referredId) {
  const referral = getReferralByCode(code);
  if (!referral || referral.redeemed) return null;
  db.prepare('UPDATE referrals SET redeemed = 1, referred_id = ? WHERE code = ?').run(referredId, code);
  return { credit: referral.credit };
}

module.exports = { createReferral, getReferralByCode, getReferralsByUser, redeemReferral };

