const router = require('express').Router();
const model  = require('./add-a-referral-system.model');

router.post('/generate', (req, res) => {
  try {
    const { user_id } = req.body;
    if (!user_id) return res.status(400).json({ error: 'user_id is required' });
    const result = model.createReferral(user_id);
    res.status(201).json(result);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

router.post('/redeem', (req, res) => {
  try {
    const { code, user_id } = req.body;
    if (!code || !user_id) return res.status(400).json({ error: 'code and user_id are required' });
    const result = model.redeemReferral(code, user_id);
    if (!result) return res.status(400).json({ error: 'Invalid or already redeemed code' });
    res.json({ success: true, credit: result.credit });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

router.get('/user/:userId', (req, res) => {
  try {
    const referrals = model.getReferralsByUser(req.params.userId);
    res.json(referrals);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

module.exports = router;

